// src/context/AuthContext.jsx
import React, { createContext, useState, useEffect, useContext } from "react"; // <--- AGREGAMOS useContext AQUÍ

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  // FORZAMOS UN USUARIO INICIAL (Bypass)
  const [user, setUser] = useState({
    nombre: "Jorlin Developer",
    email: "admin@empresa.com",
    rol: "admin",
    departamento: "Desarrollo Frontend",
  });

  const [loading, setLoading] = useState(false);

  const login = async (email, password) => {
    console.log("Bypass activado: Entrando sin validar...");
    return true;
  };

  const logout = () => setUser(null);

  return (
    <AuthContext.Provider
      value={{ user, login, logout, loading, isAuthenticated: !!user }}
    >
      {children}
    </AuthContext.Provider>
  );
};

// Hook personalizado para usar el contexto
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth debe usarse dentro de un AuthProvider");
  }
  return context;
};
